// Parse Discord webhook payload to extract search query
const content = $json.data?.content || '';
const match = content.match(/!library search (.+)/i);

if (!match) {
  return {json: {
    error: 'Invalid command format',
    expected: '!library search [query]',
    received: content
  }};
}

const query = match[1].trim();
const category = $json.data?.category || 'Fiction';

return {json: {
  search_query: query,
  subject_category: category,
  channel_id: $json.data?.channel_id,
  user_id: $json.data?.user_id,
  timestamp: new Date().toISOString()
}};

// Aggregate and rank search results
const gutenberg = $input.getByIndex(0)?.json?.results || [];
const openlibrary = $input.getByIndex(1)?.json?.docs || [];
const archive = $input.getByIndex(2)?.json?.response?.docs || [];

const query = $json.search_query.toLowerCase();

const candidates = [
  ...gutenberg.slice(0, 3).map(book => ({
    title: book.title,
    author: book.authors?.[0]?.name || 'Unknown',
    source: 'Gutenberg',
    source_url: book.cover_image,
    confidence: 0.9
  })),
  ...openlibrary.slice(0, 3).map(book => ({
    title: book.title,
    author: book.author_name?.[0] || 'Unknown',
    source: 'Open Library',
    source_url: book.key,
    confidence: 0.7
  })),
  ...archive.slice(0, 3).map(book => ({
    title: book.title,
    author: book.creator ? (Array.isArray(book.creator) ? book.creator[0] : book.creator) : 'Unknown',
    source: 'Internet Archive',
    source_url: book.identifier,
    confidence: 0.8
  }))
];

const results = candidates.sort((a, b) => b.confidence - a.confidence).slice(0, 5);

return {json: {
  search_query: $json.search_query,
  total_results: results.length,
  results: results,
  channel_id: $json.channel_id
}};

// Format results for Discord message
const results = $json.results;
const query = $json.search_query;

let description = '';
if (results.length === 0) {
  description = `No results found for "${query}"`;
} else {
  description = `Found ${results.length} results for "${query}":\n\n`;
  results.forEach((book, idx) => {
    description += `**${idx + 1}. ${book.title}**\n`;
    description += `   Author: ${book.author}\n`;
    description += `   Source: ${book.source}\n\n`;
  });
}

return {json: {
  discord_response: {
    embeds: [{
      title: '🔍 Book Search Results',
      description: description,
      color: 5793266,
      timestamp: new Date().toISOString()
    }]
  },
  channel_id: $json.channel_id
}};
